svg.script:
const KEY='woodland_outer_sheet_svg_v1';
const fields=[...document.querySelectorAll('.field')];
let active=null; let data={};
try{data=JSON.parse(localStorage.getItem(KEY)||'{}')}catch(e){data={}}
function render(g){const id=g.dataset.id; const v=data[id]||''; g.querySelector('.value').textContent=v; g.classList.toggle('filled',!!v)}
function save(){localStorage.setItem(KEY,JSON.stringify(data))}
function activate(g){if(active)active.classList.remove('active'); active=g; g.classList.add('active'); g.focus()}
fields.forEach(g=>{render(g); g.addEventListener('click',()=>activate(g)); g.addEventListener('focus',()=>activate(g));});
document.addEventListener('keydown',e=>{if(!active)return; const id=active.dataset.id;
 if(e.key==='Escape'){active.classList.remove('active'); active=null; return}
 if(e.key==='Backspace'){data[id]=(data[id]||'').slice(0,-1); render(active); save(); e.preventDefault(); return}
 if(e.key==='Delete'){data[id]=''; render(active); save(); e.preventDefault(); return}
 if(e.key==='Enter'||e.key==='Tab'){activate(fields[(fields.indexOf(active)+1)%fields.length]); e.preventDefault(); return}
 if(e.key.length===1&&!e.metaKey&&!e.ctrlKey&&!e.altKey){data[id]=(data[id]||'')+e.key; render(active); save(); e.preventDefault();}
});
